import{_ as e,o as a,c as t,a7 as o}from"./chunks/framework.C4ZIv4ii.js";const g=JSON.parse('{"title":"Installing FalconCMS Pro","description":"","frontmatter":{},"headers":[],"relativePath":"guide/pro.md","filePath":"guide/pro.md","lastUpdated":1783953426000}'),i={name:"guide/pro.md"};function n(r,s,l,c,h,p){return a(),t("div",null,[...s[0]||(s[0]=[o(`<h1 id="installing-falconcms-pro" tabindex="-1">Installing FalconCMS Pro <a class="header-anchor" href="#installing-falconcms-pro" aria-label="Permalink to &quot;Installing FalconCMS Pro&quot;">​</a></h1><p>FalconCMS is <strong>open-core</strong>. The free <code>falconcms/falconcms</code> package (MIT, on public Packagist) gives you the CMS, page builder, themes, menus, media and hooks API.</p><p><strong>Pro</strong> unlocks the commercial features:</p><ul><li><strong>E-commerce</strong> — storefront, cart, checkout, orders, coupons</li><li><strong>Multi-language</strong> — translated content and language switching</li><li><strong>Analytics</strong> — dashboard insights and reports</li><li><strong>Advanced page builder</strong> — the Pro elements, Library and Global Sections</li><li><strong>Custom fields</strong> — ACPT field groups</li><li><strong>Advanced login</strong> — multi-device &amp; magic login</li></ul><p>Pro ships as a separate, proprietary package — <code>falconcms/pro</code> — delivered from a <strong>private repository</strong>. It is never bundled in the free download, so you install it with Composer using the credentials you receive when you buy a license.</p><div class="tip custom-block"><p class="custom-block-title">You need two things</p><ol><li>A <strong>license key</strong> (<code>PRO-…</code> or <code>AGENCY-…</code>) — activates the features inside the dashboard.</li><li>An <strong>access token</strong> — lets Composer download the private <code>falconcms/pro</code> package.</li></ol><p>Both are emailed to you right after purchase. The license key is public-facing; <strong>keep the access token secret</strong> — treat it like a password.</p></div><p>Downloading the code and unlocking the features are <strong>two separate steps</strong>: the access token gets the code onto your server (Composer), and the license key turns the features on (in the dashboard).</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li>FalconCMS core <strong>v2.0</strong> or higher (<code>composer show falconcms/falconcms</code>)</li><li>PHP <strong>8.1+</strong></li><li>Composer <strong>2.x</strong></li></ul><p>If you are on core v1.x, <a href="/falconcms/guide/upgrade.html">upgrade to v2</a> first.</p><h2 id="install-from-the-dashboard-recommended" tabindex="-1">Install from the dashboard (recommended) <a class="header-anchor" href="#install-from-the-dashboard-recommended" aria-label="Permalink to &quot;Install from the dashboard (recommended)&quot;">​</a></h2><p>FalconCMS can install Pro for you — no terminal needed:</p><ol><li>Open your dashboard → <strong>Falcon Builder → License</strong>.</li><li>Paste your <strong>license key</strong> (<code>PRO-…</code> or <code>AGENCY-…</code>) and click <strong>Activate</strong>. The key is saved; the page notes that the Pro package still needs installing.</li><li>In the same page, paste your <strong>access token</strong> and click <strong>Save token &amp; install Pro</strong>. FalconCMS writes your <code>auth.json</code>, adds the private repository and runs <code>composer require falconcms/pro</code> on the server (this can take up to a minute).</li><li>Reload the page — the status card turns green and every Pro feature unlocks.</li></ol><p>That&#39;s the whole flow. Under the hood it does exactly the manual steps below, so use those if your host blocks server-side Composer (some shared hosts disable <code>exec()</code>).</p><h2 id="install-manually-fallback" tabindex="-1">Install manually (fallback) <a class="header-anchor" href="#install-manually-fallback" aria-label="Permalink to &quot;Install manually (fallback)&quot;">​</a></h2><p>Run these in your project root, using the <strong>access token</strong> from your purchase email.</p><p><strong>1. Add the private repository:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> repositories.falconcms-pro</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vcs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/falconcms/falconcms-pro.git</span></span></code></pre></div><p><strong>2. Create an <code>auth.json</code></strong> next to <code>composer.json</code> (Composer reads it automatically — a file avoids copy-paste/escaping issues with the long token):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;github-oauth&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;github.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;YOUR-ACCESS-TOKEN&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Never commit the token</p><p>Add <code>auth.json</code> to your <code>.gitignore</code>. For servers and CI, see <a href="#deploying-to-production">Deploying to production</a>.</p></div><p><strong>3. Install:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> require</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> falconcms/pro</span></span></code></pre></div><p><strong>4. Activate:</strong> dashboard → <strong>Falcon Builder → License</strong> → paste your license key → <strong>Activate</strong>.</p><h2 id="updating-pro" tabindex="-1">Updating Pro <a class="header-anchor" href="#updating-pro" aria-label="Permalink to &quot;Updating Pro&quot;">​</a></h2><h3 id="from-the-dashboard" tabindex="-1">From the dashboard <a class="header-anchor" href="#from-the-dashboard" aria-label="Permalink to &quot;From the dashboard&quot;">​</a></h3><p>Pro updates ride along with the core updater — <strong>Dashboard → Updates → Run Update Now</strong> refreshes both. To bump only Pro, re-run the install (or use the command below).</p><h3 id="manually" tabindex="-1">Manually <a class="header-anchor" href="#manually" aria-label="Permalink to &quot;Manually&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> falconcms/pro</span></span></code></pre></div><p>Or update both together:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> falconcms/falconcms</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> falconcms/pro</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Keep core and Pro in step</p><p>Pro requires a matching core major version. When you move to a new core major (e.g. v2 → v3), update both at once so their constraints resolve.</p></div><h2 id="deploying-to-production" tabindex="-1">Deploying to production <a class="header-anchor" href="#deploying-to-production" aria-label="Permalink to &quot;Deploying to production&quot;">​</a></h2><p>Your production server and CI pipeline also need the access token to install Pro. Pick whichever fits your setup — <strong>do not</strong> hard-code the token in tracked files.</p><p><strong>Option A — <code>auth.json</code> on the server</strong> (git-ignored):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;github-oauth&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;github.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;YOUR-ACCESS-TOKEN&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Option B — environment variable</strong> (great for CI / Docker):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> COMPOSER_AUTH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;{&quot;github-oauth&quot;:{&quot;github.com&quot;:&quot;YOUR-ACCESS-TOKEN&quot;}}&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-dev</span></span></code></pre></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p><strong>“Access token saved, but the Pro package could not be installed automatically.”</strong> Your host can&#39;t run Composer from the browser (or the project isn&#39;t writable). The token is still saved — just follow <a href="#install-manually-fallback">Install manually</a>, starting at step 1.</p><p><strong>“This license key is not valid.”</strong> The key wasn&#39;t recognised. Double-check you pasted it in full (no spaces). If it still fails, deactivate and try again, or contact support with your order reference.</p><p><strong>“This license key has reached its activation limit.”</strong> The key is already active on another site (Pro allows one site). Deactivate it there first — <strong>Falcon Builder → License → Deactivate</strong> frees the slot so you can activate here.</p><p><strong>“Key saved, but Pro is not active.”</strong> The key is valid but the <code>falconcms/pro</code> package isn&#39;t installed yet. Paste your access token on the License page (or <a href="#install-manually-fallback">install manually</a>).</p><p><strong>Composer: <code>Could not authenticate</code> / <code>404</code> on github.com</strong> The access token is missing or wrong. Re-check your <code>auth.json</code>, and confirm the token from your purchase email hasn&#39;t been revoked.</p><div class="tip custom-block"><p class="custom-block-title">Lost your key or token?</p><p>Contact support with your order reference. A leaked access token can be revoked and reissued without affecting your license key.</p></div>`,45)])])}const u=e(i,[["render",n]]);export{g as __pageData,u as default};
